try
{
    var response = await Client.GetAsync($"http://127.0.0.1:{port}/health");
    Assert.Equal(HttpStatusCode.OK, response.StatusCode);
    Assert.Equal("application/json", response.Content.Headers.ContentType?.MediaType);

