    using var doc = JsonDocument.Parse(body);
    Assert.Equal("ok", doc.RootElement.GetProperty("status").GetString());
    Assert.Equal("Visual Relay", doc.RootElement.GetProperty("app").GetString());
}
finally
{
    server.Stop();
}

